type token = TIdent of string | TInt of int | TPct of int | TMinus | TLArrow | TRArrow | TLParen | TRParen | TLBrace | TRBrace | TComma | TUnderscore | THash of string | TLiteral of string | TUnknown of int | TEOF | TMint
let token_name t = match t with TIdent s -> "ident:" ^ s | TInt n -> "int:" ^ string_of_int n | TPct n -> "pct:" ^ string_of_int n | TMinus -> "minus" | TLArrow -> "larrow" | TRArrow -> "rarrow" | TLParen -> "lparen" | TRParen -> "rparen" | TLBrace -> "lbrace" | TRBrace -> "rbrace" | TComma -> "comma" | TUnderscore -> "slot" | THash s -> "comment:" ^ s | TLiteral s -> "lit:" ^ s | TUnknown n -> "unknown:" ^ string_of_int n | TEOF -> "eof" | TMint -> "mint"
let is_error_node n = match n with Ast.AError s -> true | _ -> false
let rec skip_trivia toks = match toks with [] -> [] | h :: t -> (match h with THash _ -> skip_trivia t | _ -> toks)
let is_expand_token t = match t with TIdent s -> s = "expand" | TLiteral s -> s = "expand" | _ -> false
let is_syntax_head toks = match toks with TMint :: TIdent s :: t -> s = "syntax" | TMint :: TLiteral s :: t -> s = "syntax" | _ -> false
let rec has_assign toks = match toks with [] -> false | h :: t -> (match h with TLArrow -> true | TEOF -> false | _ -> has_assign t)
let rec token_names_until_eof toks acc = match toks with [] -> List.rev acc | h :: t -> (match h with TEOF -> List.rev acc | THash _ -> token_names_until_eof t acc | _ -> token_names_until_eof t ((token_name h) :: acc))
let rec drop_count toks n = if n = 0 then toks else (match toks with [] -> [] | h :: t -> drop_count t (n - 1))
let syntax_match_node mode template expansion slots = Ast.AStmt ("syntax-match", [Ast.AGroup ("mode", [mode]); Ast.AGroup ("template", template); Ast.AGroup ("slots", slots); Ast.AGroup ("expansion", expansion)])
let rec parse_group_items kind close_tok toks acc = match toks with [] -> (Ast.AError ("unterminated-" ^ kind), []) | h :: t -> if h = close_tok then (Ast.AGroup (kind, List.rev acc), t) else (match h with TEOF -> (Ast.AError ("unterminated-" ^ kind), toks) | TUnknown n -> (Ast.AError ("unknown-token:" ^ string_of_int n), t) | THash _ -> parse_group_items kind close_tok t acc | _ -> parse_group_items kind close_tok t ((token_name h) :: acc))
let rec parse_kernel_items toks acc = match toks with [] -> (Ast.AStmt ("kernel", List.rev acc), []) | h :: t -> (match h with TEOF -> (Ast.AStmt ("kernel", List.rev acc), toks) | THash _ -> parse_kernel_items t acc | TUnknown n -> (Ast.AError ("unknown-token:" ^ string_of_int n), t) | TLParen -> let pair = parse_group_items "paren" TRParen t [] in let node = fst pair in let rest = snd pair in if is_error_node node then (node, rest) else parse_kernel_items rest (node :: acc) | TLBrace -> let pair = parse_group_items "brace" TRBrace t [] in let node = fst pair in let rest = snd pair in if is_error_node node then (node, rest) else parse_kernel_items rest (node :: acc) | _ -> parse_kernel_items t ((Ast.AAtom (token_name h)) :: acc))
let rec parse_expansion toks acc = match toks with [] -> (Ast.AGroup ("expansion", List.rev acc), []) | h :: t -> (match h with TEOF -> (Ast.AGroup ("expansion", List.rev acc), toks) | THash _ -> parse_expansion t acc | TUnknown n -> (Ast.AError ("unknown-token:" ^ string_of_int n), t) | _ -> parse_expansion t ((token_name h) :: acc))
let finish_template stmt_kind mode template_items exp rest = match exp with Ast.AGroup (kind, expansion_items) -> let _ = Registry.add_syntax mode template_items expansion_items in (Ast.AStmt (stmt_kind, [Ast.AGroup ("template", template_items); exp]), rest) | _ -> (Ast.AError "syntax-bad-expansion", rest)
let parse_expand_template t acc = let pair = parse_expansion t [] in let exp = fst pair in let rest = snd pair in if is_error_node exp then (exp, rest) else finish_template "syntax-expand" "expand" (List.rev acc) exp rest
let parse_verb_template t acc = let pair = parse_expansion t [] in let exp = fst pair in let rest = snd pair in if is_error_node exp then (exp, rest) else finish_template "syntax-verb" "verb" (List.rev acc) exp rest
let rec parse_template toks acc = match toks with [] -> (Ast.AError "syntax-missing-expansion", []) | h :: t -> if is_expand_token h then parse_expand_template t acc else if h = TRArrow then parse_verb_template t acc else if h = TEOF then (Ast.AError "syntax-missing-expansion", toks) else (match h with THash _ -> parse_template t acc | TUnknown n -> (Ast.AError ("unknown-token:" ^ string_of_int n), t) | _ -> parse_template t ((token_name h) :: acc))
let parse_syntax toks = match toks with TMint :: TIdent s :: t -> parse_template t [] | TMint :: TLiteral s :: t -> parse_template t [] | _ -> (Ast.AError "expected-syntax-head", toks)
let parse_statement toks = match toks with [] -> (Ast.AError "expected-token", []) | h :: t -> (match h with TEOF -> (Ast.AError "expected-token", toks) | THash _ -> (Ast.AError "expected-token", t) | TUnknown n -> (Ast.AError ("unknown-token:" ^ string_of_int n), t) | _ -> if is_syntax_head toks then parse_syntax toks else (match Registry.find_syntax_match (token_names_until_eof toks []) with Registry.SyntaxMatch (mode, template, expansion, slots, consumed) -> (syntax_match_node mode template expansion slots, drop_count toks consumed) | Registry.NoSyntaxMatch -> let pair = parse_kernel_items toks [] in let node = fst pair in let rest = snd pair in if is_error_node node then (node, rest) else if has_assign toks then (match node with Ast.AStmt (kind, xs) -> (Ast.AStmt ("assign", xs), rest) | _ -> (node, rest)) else (match node with Ast.AStmt (kind, xs) -> if h = TMint then (Ast.AStmt ("mint", xs), rest) else (node, rest) | _ -> (node, rest))))
let rec parse_program toks acc = let rest = skip_trivia toks in match rest with [] -> Ast.AProgram (List.rev acc) | h :: t -> (match h with TEOF -> Ast.AProgram (List.rev acc) | _ -> let pair = parse_statement rest in let node = fst pair in let after = snd pair in if is_error_node node then node else parse_program after (node :: acc))
let parse toks = parse_program toks []
